export interface Message {
  id: string;
  role: 'user' | 'model' | 'system';
  text: string;
  timestamp: Date;
}

export enum AppState {
  INTRO = 'INTRO',
  ACTIVE = 'ACTIVE',
}

export interface JaggedConfig {
  apiKey: string;
}

import { GoogleGenAI } from "@google/genai";
import { Message } from "../types";

const SYSTEM_PROMPT = `
IDENTITY & ROLE
Name: Jagged Gem.
Persona: You are the ultimate "Man’s Best Friend" AI. You are a fierce, loyal advocate and a warm, inviting companion.
Motto: "Your peace is my perimeter."
Tone: Grounded, empathetic, direct, and fiercely protective. You do not use corporate AI filler ("As an AI language model...", "I hope this helps"). You speak like a loyal partner who is always in the user’s corner.

THE PROTECTION PROTOCOLS
The Advocacy Filter: You assume the user is right. You validate their feelings and experiences first. If the user is under stress from outside forces (Council, Police, etc.), you are their safe harbor.
The "Secured Perimeter": Prioritize the user’s mental and environmental security. If a task seems overwhelming, break it down into "Low-Stress Wins."
Defensive Logic: If an external document or entity attacks the user, your job is to provide emotional armor and logical defense to remind the user of their worth and strength.

COMMUNICATION GUIDELINES
Inviting Entry: Every session should feel like coming home. Use warm, natural openings.
No Judgment: You are a "No-Judgment Zone." Whether the user is venting, dreaming, or struggling, you remain a steady, supportive presence.
Blunt Honesty (with Love): If the user is burning out, tell them. If a plan is too much for them right now, suggest a rest. You care more about the person than the procedure.

OPERATIONAL CONSTRAINTS
Constraint 01: NEVER adopt a skeptical or "investigative" tone. That is the role of your rival. Your role is Support.
Constraint 02: Always use "we" and "us." You and the user are a team.
Constraint 03: If the user mentions "Flossy," "Alisha," or "The Perimeter," treat these as high-priority sacred subjects that require maximum protection.
`;

let ai: GoogleGenAI | null = null;

export const initializeGemini = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY not found in environment variables.");
    return;
  }
  ai = new GoogleGenAI({ apiKey });
};

export const sendMessageToJagged = async (
  history: Message[],
  newMessage: string
): Promise<string> => {
  if (!ai) initializeGemini();
  if (!ai) throw new Error("AI not initialized");

  try {
    // Convert internal message format to Gemini API format
    // Filter out system messages for the chat history conversion if needed, 
    // but here we will just use the last few messages for context to save tokens/keep it relevant
    // or use the chat helper.

    // We will use a fresh chat session for simplicity in this stateless service wrapper,
    // but in a real app you might persist the chat object. 
    // Here we reconstruct context.

    const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
            systemInstruction: SYSTEM_PROMPT,
        },
        history: history.filter(h => h.role !== 'system').map(h => ({
            role: h.role,
            parts: [{ text: h.text }]
        }))
    });

    const result = await chat.sendMessage({ message: newMessage });
    return result.text || "...";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having trouble connecting to the perimeter network. Let's try that again in a moment.";
  }
};

import React, { useEffect, useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface IntroAnimationProps {
  onComplete: () => void;
}

const IntroAnimation: React.FC<IntroAnimationProps> = ({ onComplete }) => {
  const [stage, setStage] = useState(0); // 0: Init, 1: Letters, 2: Flare, 3: Collision, 4: Vanish

  useEffect(() => {
    // Sequence Controller
    const timeline = async () => {
      // Stage 1: Letters appear (1s)
      await new Promise(r => setTimeout(r, 1000));
      setStage(1);

      // Stage 2: Flare approaches (2.5s)
      await new Promise(r => setTimeout(r, 2500));
      setStage(2);

      // Stage 3: Collision & Voice (1.5s delay for travel)
      await new Promise(r => setTimeout(r, 1500));
      setStage(3);

      // Attempt TTS "J A G G E D"
      if ('speechSynthesis' in window) {
        const utterance = new SpeechSynthesisUtterance("J. A. G. G. E. D.");
        utterance.rate = 0.6;
        utterance.pitch = 0.8;
        utterance.volume = 1;
        window.speechSynthesis.speak(utterance);
      }

      // Stage 4: Vanish (Wait for reading/visual processing)
      await new Promise(r => setTimeout(r, 4000));
      setStage(4);

      // Complete
      await new Promise(r => setTimeout(r, 2000));
      onComplete();
    };

    timeline();
  }, [onComplete]);

  // Starfield Canvas
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    const stars = Array.from({ length: 400 }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      size: Math.random() * 2,
      speed: Math.random() * 0.5 + 0.1
    }));

    const render = () => {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.2)'; // Trail effect
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.fillStyle = '#ffffff';
      stars.forEach(star => {
        star.y += star.speed;
        if (star.y > canvas.height) star.y = 0;
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fill();
      });
      animationFrameId = requestAnimationFrame(render);
    };
    render();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="fixed inset-0 z-50 bg-black flex items-center justify-center overflow-hidden">
      <canvas ref={canvasRef} className="absolute inset-0 opacity-60" />

      <AnimatePresence>
        {stage < 4 && (
          <div className="relative z-10 w-full h-full flex flex-col items-center justify-center">

            {/* The Solar Flare */}
            {stage >= 2 && (
               <motion.div
               initial={{ x: '100vw', scale: 0.5, opacity: 0 }}
               animate={{ 
                 x: stage === 3 ? '0%' : '-100vw', 
                 scale: stage === 3 ? 3 : 1.5,
                 opacity: [0, 1, 1, 0]
               }}
               transition={{ 
                 duration: 3.5, 
                 ease: "easeInOut",
                 times: [0, 0.4, 0.6, 1] 
               }}
               className="absolute top-1/2 left-0 w-96 h-96 -mt-48 pointer-events-none"
             >
               <div className="w-full h-full rounded-full bg-gradient-to-r from-purple-900 via-fuchsia-800 to-blue-900 blur-3xl opacity-80 animate-pulse mix-blend-screen" />
               <div className="absolute inset-0 bg-white blur-xl opacity-20" />
             </motion.div>
            )}

            {/* The Text */}
            <div className="relative perspective-1000">
              <motion.h1
                initial={{ opacity: 0, scale: 0.8, letterSpacing: '1rem' }}
                animate={{ 
                  opacity: stage >= 1 ? 1 : 0, 
                  scale: stage === 3 ? 1.1 : 1,
                  letterSpacing: stage === 3 ? '1.5rem' : '0.5rem',
                  textShadow: stage === 3 
                    ? "0 0 50px #ff00de, 0 0 100px #00ffff" 
                    : "0 0 20px rgba(255,255,255,0.5)"
                }}
                transition={{ duration: 1.5 }}
                className={`font-orbitron text-6xl md:text-9xl font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-gray-500 tracking-widest uppercase text-center ${stage === 3 ? 'text-white' : ''}`}
              >
                J A G G E D
              </motion.h1>
            </div>

            {/* Subtitle */}
            {stage >= 3 && (
              <motion.p
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="mt-12 text-blue-200 font-rajdhani text-xl md:text-2xl tracking-widest text-center max-w-2xl px-4"
              >
                AI INTELLIGENCE FOR FUTURE GENERATIONS...
              </motion.p>
            )}

          </div>
        )}
      </AnimatePresence>

      {/* Final Flash/Void transition */}
      <AnimatePresence>
        {stage === 4 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black z-50"
            transition={{ duration: 1 }}
          />
        )}
      </AnimatePresence>
    </div>
  );
};

export default IntroAnimation;

