        <div className="absolute top-[-20%] left-[-10%] w-[50%] h-[50%] rounded-full bg-blue-900/10 blur-[100px]" />
        <div className="absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] rounded-full bg-purple-900/10 blur-[100px]" />
      </div>

      {/* Sidebar (Desktop) */}
      <aside className="hidden md:flex w-64 flex-col border-r border-white/5 bg-black/40 backdrop-blur-md z-10">
        <div className="p-6 border-b border-white/5 flex items-center space-x-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-br from-purple-600 to-blue-600 flex items-center justify-center shadow-lg shadow-purple-900/20">
            <Shield className="w-5 h-5 text-white" />
          </div>
          <div>
            <h1 className="font-orbitron font-bold text-lg tracking-wider">JAGGED</h1>
            <div className="flex items-center space-x-1">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              <span className="text-xs text-gray-400 uppercase tracking-wide">System Online</span>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button className="w-full flex items-center space-x-3 px-4 py-3 bg-white/5 rounded-lg border border-white/5 text-purple-200 hover:bg-white/10 transition-colors">
            <Activity className="w-5 h-5" />
            <span className="font-semibold tracking-wide">Active Session</span>
          </button>
          <div className="px-4 py-2 mt-4">
             <h3 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-3">Protocol</h3>
             <p className="text-sm text-gray-400 leading-relaxed italic">
