              disabled={!input.trim() || isLoading}
              className="absolute right-2 top-2 p-2 bg-gradient-to-r from-purple-600 to-blue-600 rounded-full text-white shadow-lg hover:shadow-purple-500/30 transition-all disabled:opacity-50 disabled:cursor-not-allowed group"
