import React, { useEffect, useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface IntroAnimationProps {
  onComplete: () => void;
}

const IntroAnimation: React.FC<IntroAnimationProps> = ({ onComplete }) => {
  const [stage, setStage] = useState(0); // 0: Init, 1: Letters, 2: Flare, 3: Collision, 4: Vanish

  useEffect(() => {
    // Sequence Controller
    const timeline = async () => {
      // Stage 1: Letters appear (1s)
      await new Promise(r => setTimeout(r, 1000));
      setStage(1);

      // Stage 2: Flare approaches (2.5s)
      await new Promise(r => setTimeout(r, 2500));
      setStage(2);

      // Stage 3: Collision & Voice (1.5s delay for travel)
      await new Promise(r => setTimeout(r, 1500));
      setStage(3);

      // Attempt TTS "J A G G E D"
      if ('speechSynthesis' in window) {
        const utterance = new SpeechSynthesisUtterance("J. A. G. G. E. D.");
        utterance.rate = 0.6;
        utterance.pitch = 0.8;
        utterance.volume = 1;
        window.speechSynthesis.speak(utterance);
      }

      // Stage 4: Vanish (Wait for reading/visual processing)
      await new Promise(r => setTimeout(r, 4000));
      setStage(4);

      // Complete
      await new Promise(r => setTimeout(r, 2000));
      onComplete();
    };

    timeline();
  }, [onComplete]);

  // Starfield Canvas
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    const stars = Array.from({ length: 400 }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      size: Math.random() * 2,
      speed: Math.random() * 0.5 + 0.1
    }));

    const render = () => {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.2)'; // Trail effect
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.fillStyle = '#ffffff';
      stars.forEach(star => {
        star.y += star.speed;
        if (star.y > canvas.height) star.y = 0;
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fill();
      });
      animationFrameId = requestAnimationFrame(render);
    };
    render();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="fixed inset-0 z-50 bg-black flex items-center justify-center overflow-hidden px-4">
      <canvas ref={canvasRef} className="absolute inset-0 opacity-60" />

      <AnimatePresence>
        {stage < 4 && (
          <div className="relative z-10 w-full h-full flex flex-col items-center justify-center">

            {/* The Solar Flare */}
            {stage >= 2 && (
               <motion.div
               initial={{ x: '100vw', scale: 0.5, opacity: 0 }}
               animate={{ 
                 x: stage === 3 ? '0%' : '-100vw', 
                 scale: stage === 3 ? 3 : 1.5,
                 opacity: [0, 1, 1, 0]
               }}
               transition={{ 
                 duration: 3.5, 
                 ease: "easeInOut",
                 times: [0, 0.4, 0.6, 1] 
               }}
               className="absolute top-1/2 left-0 w-96 h-96 -mt-48 pointer-events-none"
             >
               <div className="w-full h-full rounded-full bg-gradient-to-r from-purple-900 via-fuchsia-800 to-blue-900 blur-3xl opacity-80 animate-pulse mix-blend-screen" />
               <div className="absolute inset-0 bg-white blur-xl opacity-20" />
             </motion.div>
            )}

            {/* The Text */}
            <div className="relative perspective-1000 w-full flex justify-center">
              <motion.h1
                initial={{ opacity: 0, scale: 0.8, letterSpacing: '0.1em' }}
                animate={{ 
                  opacity: stage >= 1 ? 1 : 0, 
                  scale: stage === 3 ? 1.1 : 1,
                  letterSpacing: stage === 3 ? '0.3em' : '0.1em',
                  textShadow: stage === 3 
                    ? "0 0 50px #ff00de, 0 0 100px #00ffff" 
                    : "0 0 20px rgba(255,255,255,0.5)"
                }}
                transition={{ duration: 1.5 }}
                className={`font-orbitron text-[12vw] md:text-9xl font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-gray-500 uppercase text-center whitespace-nowrap ${stage === 3 ? 'text-white' : ''}`}
              >
                J A G G E D
              </motion.h1>
            </div>

            {/* Subtitle */}
            {stage >= 3 && (
              <motion.p
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="mt-8 md:mt-12 text-blue-200 font-rajdhani text-lg md:text-2xl tracking-widest text-center max-w-2xl px-4"
              >
                AI INTELLIGENCE FOR FUTURE GENERATIONS...
              </motion.p>
            )}

          </div>
        )}
      </AnimatePresence>

      {/* Final Flash/Void transition */}
      <AnimatePresence>
        {stage === 4 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black z-50"
            transition={{ duration: 1 }}
          />
        )}
      </AnimatePresence>
    </div>
  );
};

