import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { motion } from 'framer-motion';
import { Mic, MicOff, X, Activity, Shield, Volume2 } from 'lucide-react';

interface LiveInterfaceProps {
  onClose: () => void;
  systemInstruction: string;
}

const LiveInterface: React.FC<LiveInterfaceProps> = ({ onClose, systemInstruction }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [isMicOn, setIsMicOn] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [volumeLevel, setVolumeLevel] = useState(0); // For visualization

  // Refs for audio handling to avoid re-renders
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionRef = useRef<any>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    let isMounted = true;

    const startSession = async () => {
      try {
        const apiKey = process.env.API_KEY;
        if (!apiKey) throw new Error("API Key not found");

        const ai = new GoogleGenAI({ apiKey });

        // Input Audio Context (16kHz for Gemini)
        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        inputContextRef.current = inputCtx;

        // Output Audio Context (24kHz for Gemini response)
        const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        audioContextRef.current = outputCtx;

        // Get Microphone Stream
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        streamRef.current = stream;

        // Connect to Gemini Live
        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          config: {
            responseModalities: [Modality.AUDIO],
            systemInstruction: systemInstruction,
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Fenrir' } }, // Deep, strong voice fits Jagged
            },
          },
          callbacks: {
            onopen: () => {
              if (!isMounted) return;
              setIsConnected(true);
              console.log("JAGGED LIVE: Connected");

              // Setup Input Processing
              const source = inputCtx.createMediaStreamSource(stream);
              sourceRef.current = source;

              // ScriptProcessor for raw PCM access (bufferSize, inputChannels, outputChannels)
              const processor = inputCtx.createScriptProcessor(4096, 1, 1);
              processorRef.current = processor;

              processor.onaudioprocess = (e) => {
                if (!isMicOn) return; // Mute logic

                const inputData = e.inputBuffer.getChannelData(0);

                // Simple volume meter logic
                let sum = 0;
                for(let i=0; i<inputData.length; i++) sum += inputData[i] * inputData[i];
                const rms = Math.sqrt(sum / inputData.length);
                setVolumeLevel(v => Math.max(0.1, rms * 5)); // Scaling for visual

                // Create PCM Blob and Send
                const pcmBlob = createPcmBlob(inputData);
                sessionPromise.then((session) => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(processor);
              processor.connect(inputCtx.destination);
            },
            onmessage: async (msg: LiveServerMessage) => {
              if (!isMounted) return;

              // Handle Audio Output
              const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
              if (base64Audio && audioContextRef.current) {
                const ctx = audioContextRef.current;

                // Decode
                const audioData = decodeBase64(base64Audio);
                const audioBuffer = await decodeAudioData(audioData, ctx, 24000, 1);

                // Schedule Playback
                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                const source = ctx.createBufferSource();
                source.buffer = audioBuffer;
                source.connect(ctx.destination);
                source.start(nextStartTimeRef.current);

                nextStartTimeRef.current += audioBuffer.duration;
              }

              // Handle Interruption
              if (msg.serverContent?.interrupted) {
                nextStartTimeRef.current = 0;
                // Note: In a full implementation, we would track and stop active nodes.
                // For this snippet, we reset the cursor.
              }
            },
            onclose: () => {
              console.log("JAGGED LIVE: Closed");
              if(isMounted) setIsConnected(false);
            },
            onerror: (err) => {
              console.error("JAGGED LIVE Error:", err);
              if(isMounted) setError("Connection Perimeter Breached.");
            }
          }
        });

        sessionRef.current = sessionPromise;

      } catch (err) {
        console.error(err);
        setError("Audio System Failure. Check Permissions.");
      }
    };

    startSession();

    return () => {
      isMounted = false;
      // Cleanup
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (processorRef.current) processorRef.current.disconnect();
      if (sourceRef.current) sourceRef.current.disconnect();
      if (inputContextRef.current) inputContextRef.current.close();
      if (audioContextRef.current) audioContextRef.current.close();
      // We can't strictly "close" the session promise object from here, 
      // but the onclose callback handles state.
    };
  }, [systemInstruction]); // Depend on systemInstruction to restart if it changes (unlikely)

  // -- Helpers --

  // Convert Float32Array to 16-bit PCM Blob
  const createPcmBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    const uint8 = new Uint8Array(int16.buffer);

    // Manual binary string construction for btoa (avoiding text encoder for binary)
    let binary = '';
    const len = uint8.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(uint8[i]);
    }
    const base64 = btoa(binary);

    return {
      data: base64,
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const decodeBase64 = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const decodeAudioData = async (
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
  ): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  return (
    <div className="absolute inset-0 z-50 bg-black/95 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-500">

      {/* Background Ambience */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-purple-900/10 rounded-full blur-3xl animate-pulse" />
      </div>

      <div className="relative z-10 flex flex-col items-center w-full max-w-md px-6">

        {/* Header */}
        <div className="flex items-center space-x-2 mb-12 opacity-80">
          <Activity className="w-5 h-5 text-purple-400" />
          <span className="font-orbitron tracking-widest text-sm text-purple-200">LIVE PERIMETER ACTIVE</span>
        </div>

        {/* Central Visualizer */}
        <div className="relative mb-16">
          {/* Outer Ring */}
          <motion.div 
            animate={{ scale: isConnected ? [1, 1.1, 1] : 1, opacity: isConnected ? 0.5 : 0.2 }}
            transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
            className="absolute inset-0 rounded-full border border-purple-500/30 w-64 h-64 -m-16"
          />

          {/* Inner Ring (Volume Reactive) */}
          <motion.div 
            animate={{ scale: 1 + volumeLevel }}
            className="absolute inset-0 rounded-full border border-blue-400/40 w-48 h-48 -m-8"
          />

          {/* Core Orb */}
          <motion.div
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            className="w-32 h-32 bg-gradient-to-br from-purple-600 to-blue-900 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(147,51,234,0.5)] relative overflow-hidden"
          >
            <Shield className="w-12 h-12 text-white/90 z-10" />
            <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
          </motion.div>
        </div>

        {/* Status Text */}
        <div className="h-8 mb-8 text-center">
          {error ? (
             <span className="text-red-400 font-rajdhani font-bold tracking-widest">{error}</span>
          ) : !isConnected ? (
             <span className="text-gray-400 animate-pulse font-rajdhani tracking-widest">ESTABLISHING SECURE LINK...</span>
          ) : (
             <span className="text-blue-200 font-rajdhani tracking-widest flex items-center gap-2">
               <Volume2 className="w-4 h-4" />
               JAGGED IS LISTENING
             </span>
          )}
        </div>

        {/* Controls */}
        <div className="flex items-center gap-6">
           <button 
             onClick={() => setIsMicOn(!isMicOn)}
             className={`p-4 rounded-full border transition-all ${isMicOn ? 'bg-white/10 border-white/20 text-white hover:bg-white/20' : 'bg-red-900/20 border-red-500/50 text-red-400'}`}
           >
             {isMicOn ? <Mic className="w-6 h-6" /> : <MicOff className="w-6 h-6" />}
           </button>

           <button 
             onClick={onClose}
             className="px-8 py-4 bg-red-600/20 border border-red-500/50 hover:bg-red-600/40 text-red-100 rounded-full font-bold tracking-wider transition-all flex items-center gap-2"
           >
             <X className="w-5 h-5" />
             END PROTOCOL
           </button>
        </div>

      </div>
    </div>
  );
};

export default LiveInterface;

