const ChatInterface: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'init-1',
      role: 'model',
      text: "I'm online. Perimeter is secure. How are we feeling today?",
      timestamp: new Date()
    }
  ]);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [view, setView] = useState<'chat' | 'history'>('chat');
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLiveMode, setIsLiveMode] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    if (view === 'chat' && !isLiveMode) {
      scrollToBottom();
    }
  }, [messages, view, isLiveMode]);

  useEffect(() => {
    if(!isLoading && view === 'chat' && !isLiveMode) {
      inputRef.current?.focus();
    }
  }, [isLoading, view, isLiveMode]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToJagged(messages.concat(userMsg), input);

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const archiveCurrentSession = () => {
    const hasUserMessages = messages.some(m => m.role === 'user');
    if (hasUserMessages) {
      const firstUserMsg = messages.find(m => m.role === 'user');
      const title = firstUserMsg 
        ? (firstUserMsg.text.length > 30 ? firstUserMsg.text.substring(0, 30) + '...' : firstUserMsg.text)
        : 'New Session';

      const newSession: ChatSession = {
        id: Date.now().toString(),
        title,
        messages: [...messages],
        createdAt: new Date()
      };
      setSessions(prev => [newSession, ...prev]);
    }
    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      text: "New perimeter established. I'm listening.",
      timestamp: new Date()
    }]);
    setIsMobileMenuOpen(false);
